-- ==========================================================
-- SCRIPT DE CARGA SEMILLA GENERADO AUTOMATICAMENTE
-- Destino: PostgreSQL (Base de Datos: Postgres_SIGD)
-- ==========================================================

-- Limpieza previa
DELETE FROM estadistica_documento WHERE id_documento >= 101;
DELETE FROM documento_vigente WHERE id_documento >= 101;
DELETE FROM usuario WHERE id_usuario > 6;

-- Insertar departamentos faltantes
ON CONFLICT (id_departamento) DO NOTHING;

-- Insertar usuarios faltantes (IDs del 7 al 15)
ON CONFLICT (id_usuario) DO NOTHING;

-- Vincular usuarios y departamentos existentes a sus empresas
UPDATE departamento SET id_empresa = (SELECT id_empresa FROM empresa WHERE slug = 'techcorp') WHERE id_departamento IN (2, 4, 6);
UPDATE departamento SET id_empresa = (SELECT id_empresa FROM empresa WHERE slug = 'grupoinnovar') WHERE id_departamento IN (3, 5);

UPDATE usuario SET id_empresa = (SELECT id_empresa FROM empresa WHERE slug = 'techcorp') WHERE id_departamento IN (2, 4, 6);
UPDATE usuario SET id_empresa = (SELECT id_empresa FROM empresa WHERE slug = 'grupoinnovar') WHERE id_departamento IN (3, 5);

UPDATE tipo_documento SET id_empresa = (SELECT id_empresa FROM empresa WHERE slug = 'techcorp') WHERE id_tipo IN (1, 2, 3, 5);
UPDATE tipo_documento SET id_empresa = (SELECT id_empresa FROM empresa WHERE slug = 'grupoinnovar') WHERE id_tipo IN (4, 6, 7);

-- Insertar documentos


-- Insertar estadísticas iniciales

-- Resumen de inserción
DO $$
DECLARE
    total_docs    INT;
    total_users   INT;
BEGIN
    SELECT COUNT(*) INTO total_docs FROM documento_vigente WHERE id_documento >= 101;
    SELECT COUNT(*) INTO total_users FROM usuario;
    RAISE NOTICE '============================================';
    RAISE NOTICE '  SEED DATA POR POSTGRESQL APLICADO';
    RAISE NOTICE '  Documentos semilla >= 101 : %', total_docs;
    RAISE NOTICE '  Total usuarios registrados: %', total_users;
    RAISE NOTICE '============================================';
END $$;
